/**
 * Server-side Encryption at Rest
 *
 * Provides AES-256-GCM encryption for sensitive data stored in D1.
 * Key is derived from PF_TOKEN_SECRET via HKDF (not the secret directly).
 *
 * Used for: provisioned API keys, shared pool keys.
 * Format: base64url(iv).base64url(ciphertext+tag)
 */

// ============================================================
// Base64url helpers (no padding, URL-safe)
// ============================================================

function uint8ArrayToBase64Url(bytes: Uint8Array): string {
  let binary = ''
  for (let i = 0; i < bytes.length; i++) {
    binary += String.fromCharCode(bytes[i])
  }
  return btoa(binary)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '')
}

function base64UrlToUint8Array(base64url: string): Uint8Array {
  const base64 = base64url.replace(/-/g, '+').replace(/_/g, '/')
  const padding = '='.repeat((4 - (base64.length % 4)) % 4)
  const binary = atob(base64 + padding)
  return new Uint8Array(binary.split('').map((c) => c.charCodeAt(0)))
}

// ============================================================
// Key derivation (HKDF from worker secret)
// ============================================================

async function deriveKey(secret: string): Promise<CryptoKey> {
  const encoder = new TextEncoder()
  const keyMaterial = await crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    { name: 'HKDF' },
    false,
    ['deriveKey']
  )
  return crypto.subtle.deriveKey(
    {
      name: 'HKDF',
      hash: 'SHA-256',
      salt: encoder.encode('pebbleflow-key-encryption'),
      info: encoder.encode('api-key-at-rest'),
    },
    keyMaterial,
    { name: 'AES-GCM', length: 256 },
    false,
    ['encrypt', 'decrypt']
  )
}

