/**
 * Encrypt a plaintext string for storage in D1.
 * Returns `base64url(iv).base64url(ciphertext)`.
 */
export async function encryptAtRest(plaintext: string, secret: string): Promise<string> {
  const encoder = new TextEncoder()
  const key = await deriveKey(secret)

  const iv = new Uint8Array(12)
  crypto.getRandomValues(iv)

  const ciphertext = await crypto.subtle.encrypt(
    { name: 'AES-GCM', iv },
    key,
    encoder.encode(plaintext)
  )

  return `${uint8ArrayToBase64Url(iv)}.${uint8ArrayToBase64Url(new Uint8Array(ciphertext))}`
}

/**
 * Decrypt a value produced by `encryptAtRest`.
 * Throws if the secret is wrong or the ciphertext is tampered.
 */
export async function decryptAtRest(encrypted: string, secret: string): Promise<string> {
  const parts = encrypted.split('.')
  if (parts.length !== 2 || !parts[0] || !parts[1]) {
    throw new Error('Invalid encrypted format: expected iv.ciphertext')
  }

  const iv = base64UrlToUint8Array(parts[0])
  const ciphertext = base64UrlToUint8Array(parts[1])
  const key = await deriveKey(secret)

  const plaintext = await crypto.subtle.decrypt(
    { name: 'AES-GCM', iv },
    key,
    ciphertext
  )

  return new TextDecoder().decode(plaintext)
}

/**
 * Check if a string looks like an encrypted value (iv.ciphertext format).
 * Used to distinguish encrypted vs plaintext during migration.
 */
export function isEncryptedAtRest(value: string): boolean {
  const parts = value.split('.')
  if (parts.length !== 2 || !parts[0] || !parts[1]) return false
  // IV should be 12 bytes → 16 base64url chars
  // Ciphertext should be at least a few bytes
  return /^[A-Za-z0-9_-]{16}$/.test(parts[0]) && /^[A-Za-z0-9_-]+$/.test(parts[1])
}
